-- Pontos (stitches) server-driven: antes vinham de assets/data/stitches.json.
-- Agora ficam no Postgres pra poder gerenciar (e anexar vídeo da técnica) pelo painel.
CREATE TABLE IF NOT EXISTS stitches (
  id             text PRIMARY KEY,
  name_pt        text NOT NULL,
  name_en        text NOT NULL,
  abbrev         text NOT NULL DEFAULT '',
  technique      text NOT NULL CHECK (technique IN ('crochet','knit')),
  difficulty     text NOT NULL CHECK (difficulty IN ('beginner','intermediate','advanced')),
  categories     jsonb NOT NULL DEFAULT '[]',
  description    text NOT NULL DEFAULT '',
  steps          jsonb NOT NULL DEFAULT '[]',
  video_asset_id uuid REFERENCES assets(id) ON DELETE SET NULL,
  order_index    integer NOT NULL DEFAULT 0,
  created_at     timestamptz NOT NULL DEFAULT now(),
  updated_at     timestamptz NOT NULL DEFAULT now()
);

ON CONFLICT (id) DO NOTHING;
